[metadata] {"type": "create", "filePath": "/app/command/config/_rc_parser.ts", "content": "/**
 * Parse `.rc` style config content: `key=value` pairs per line, where lines
 * starting with `#` are comments, empty lines are ignored and values wrapped
 * in double quotes preserve leading/trailing spaces.
 */
export function parseRcFile(content: string): Record<string, string> {
  const result: Record<string, string> = {};

  for (const rawLine of content.split(/\r?\n/)) {
    const line = rawLine.trim();

    if (!line || line.startsWith("#")) {
      continue;
    }

    const index = line.indexOf("=");
    if (index === -1) {
      continue;
    }

    const key = line.slice(0, index).trim();
    let value = line.slice(index + 1).trim();

    if (value.length >= 2 && value.startsWith('"') && value.endsWith('"')) {
      value = value.slice(1, -1);
    }

    result[key] = value;
  }

  return result;
}
