[metadata] {"type": "create", "filePath": "/app/command/config/_utils.ts", "content": "/** Coerce a raw `.rc` string value to a boolean, number or string. */
export function coerceRcValue(value: string): unknown {
  if (value === "true") {
    return true;
  }
  if (value === "false") {
    return false;
  }
  if (value !== "" && /^-?\d+(\.\d+)?$/.test(value)) {
    return Number(value);
  }
  return value;
}

/** Convert a kebab-case string to camelCase. */
export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
}

/** Recursively flatten a nested object into dot-notation keys. */
export function flattenConfig(
  obj: Record<string, unknown>,
  prefix = "",
): Record<string, unknown> {
  const result: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null && typeof value === "object" && !Array.isArray(value)
    ) {
      Object.assign(
        result,
        flattenConfig(value as Record<string, unknown>, path),
      );
    } else {
      result[path] = value;
    }
  }

  return result;
}

/** Convert every dot-separated segment of a flattened key to camelCase. */
export function camelCaseKey(key: string): string {
  return key.split(".").map(kebabToCamelCase).join(".");
}
