import { ConfigParseError } from "./_errors.ts";
import { parseRcFile } from "./_rc_parser.ts";
import { camelCaseKey, coerceRcValue, flattenConfig } from "./_utils.ts";
import type { ConfigOptions } from "./types.ts";

export interface ResolvedConfig {
  path?: string;
  values: Record<string, unknown>;
}

interface ConfigFileMatch {
  path: string;
  format: string;
  content: string;
}

function resolveFileName(name: string, format: string): string {
  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
}

function joinPath(searchPath: string, fileName: string): string {
  return `${searchPath.replace(/[\\/]+$/, "") || "."}/${fileName}`;
}

async function tryReadFile(path: string): Promise<string | undefined> {
  try {
    return await readTextFile(path);
  } catch {
    return undefined;
  }
}

async function findConfigFile(
  searchPath: string,
  name: string,
  formats: Array<string>,
): Promise<ConfigFileMatch | undefined> {
  for (const format of formats) {
    const path = joinPath(searchPath, resolveFileName(name, format));
    const content = await tryReadFile(path);

    if (content !== undefined) {
      return { path, format, content };
    }
  }
  return undefined;
}

function parseConfigContent(
  match: ConfigFileMatch,
  parser?: ConfigOptions["parser"],
): Record<string, unknown> {
  try {
    if (parser) {
      return parser(match.content);
    }

    if (match.format === ".rc") {
      const raw = parseRcFile(match.content);
      const coerced: Record<string, unknown> = {};
      for (const [key, value] of Object.entries(raw)) {
        coerced[key] = coerceRcValue(value);
      }
      return coerced;
    }

    return JSON.parse(match.content);
  } catch (error) {
    throw new ConfigParseError(match.path, error);
  }
}

/** Find, read, parse and normalize config file(s) according to `options`. */
export async function loadConfig(
  options: ConfigOptions,
): Promise<ResolvedConfig> {
  const searchPaths = options.searchPaths?.length
    ? options.searchPaths
    : ["."];
  const formats = options.formats?.length ? options.formats : [".json", ".rc"];
  const mergeConfigs = options.mergeConfigs ?? false;

  const matches: Array<ConfigFileMatch> = [];

  for (const searchPath of searchPaths) {
    const match = await findConfigFile(searchPath, options.name, formats);

    if (match) {
      matches.push(match);
      if (!mergeConfigs) {
        break;
      }
    }
  }

  if (!matches.length) {
    return { values: {} };
  }

  // Merge from last to first so that earlier search paths take precedence.
  let merged: Record<string, unknown> = {};
  for (let i = matches.length - 1; i >= 0; i--) {
    merged = { ...merged, ...parseConfigContent(matches[i], options.parser) };
  }

  const flattened = flattenConfig(merged);
  const values: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(flattened)) {
    values[camelCaseKey(key)] = value;
  }

  return { path: matches[0].path, values };
}
