  /**
   * Load option values from a config file.
   *
   * Config values are applied as defaults: environment variables override
   * config values and CLI arguments override both.
   *
   * @param options Config options.
   */
  public config(options: ConfigOptions): this {
    if (!options?.name) {
      throw new MissingConfigNameError();
    }
    this.cmd.settings.configOptions = options;
    return this;
  }

  /** Get the resolved path of the loaded config file, if any. */
  public getConfigPath(): string | undefined {
    return this.props.configPath;
  }

  /**
   * Get the config values loaded for this command, merged with the config
   * values inherited from parent commands. Own values take precedence over
   * inherited ones. Nested config objects are flattened using dot notation.
   */
  public getConfigValues(): Record<string, unknown> {
    const parentValues = this.parent?.getConfigValues() ?? {};
    return { ...parentValues, ...(this.props.configValues ?? {}) };
  }

  /** Load and cache the config file for this command, if configured. */
  private async loadConfigValues(): Promise<void> {
    if (this.props.configLoaded) {
      return;
    }
    this.props.configLoaded = true;

    const configOptions = this.settings.configOptions;
    if (!configOptions) {
      this.props.configValues = {};
      return;
    }

    const resolved = await loadConfig(configOptions);
    this.props.configPath = resolved.path;

    for (const [key, value] of Object.entries(resolved.values)) {
      const option = this.getOption(key, true);

      if (!option) {
        continue;
      }

      if (Array.isArray(value)) {
        if (!option.collect) {
          throw new ConfigValidationError(
            key,
            `expected a single value but got an array`,
          );
        }
        continue;
      }

      const type = option.args?.[0]?.type;
      const actual = typeof value;

      if (type === "boolean" && actual !== "boolean") {
        throw new ConfigValidationError(key, `expected a boolean but got ${actual}`);
      } else if (
        (type === "number" || type === "integer") && actual !== "number"
      ) {
        throw new ConfigValidationError(key, `expected a number but got ${actual}`);
      } else if (type === "string" && actual !== "string") {
        throw new ConfigValidationError(key, `expected a string but got ${actual}`);
      }
    }

    this.props.configValues = resolved.values;
  }

